THOUGHT: The crash occurs because InstCombine creates a boolean And/Or with operands of different types: a vector compare result (<N x i1>) and a scalar select condition (i1). In foldICmpBinOpEqualityWithConstant(), for the (or (select cond, ..., ...), Other) == 0 pattern, it builds "ICmp Other, 0" and then returns BinaryOperator::Create(And/Or, Cmp, Cond). If Cond is scalar while Cmp is a vector of i1, this mismatches operand types, triggering the assertion. The fix is to splat the scalar condition to a vector of i1 matching the compare result type before creating the And/Or. I will modify both spots (for Cond and for NotCond) to splat when needed, then run submit-patch.

```bash
python3 - << 'PY' && submit-patch
import re, sys, pathlib
p = pathlib.Path("llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp")
s = p.read_text()

# Patch the first case: use Cond, may need to splat to match compare type.
s = re.sub(
    r"""Value \*Cmp = Builder\.CreateICmp\(
\s*Pred, Other, Constant::getNullValue\(Other->getType\(\)\)\);
\s*return BinaryOperator::Create\(
\s*Pred == ICmpInst::ICMP_EQ \? Instruction::And : Instruction::Or, Cmp,
\s*Cond\);""",
    """Value *CmpV = Builder.CreateICmp(
            Pred, Other, Constant::getNullValue(Other->getType()));
          Value *CondV = Cond;
          if (CmpV->getType() != Cond->getType())
            if (auto *VT = dyn_cast<VectorType>(CmpV->getType()))
              CondV = Builder.CreateVectorSplat(VT->getElementCount(), Cond);
          return BinaryOperator::Create(
              Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, CmpV,
              CondV);""",
    s, flags=re.M)

# Patch the second case: uses NotCond, also splat if needed.
s = re.sub(
    r"""Value \*Cmp = Builder\.CreateICmp\(
\s*Pred, Other, Constant::getNullValue\(Other->getType\(\)\)\);
\s*return BinaryOperator::Create\(
\s*Pred == ICmpInst::ICMP_EQ \? Instruction::And : Instruction::Or, Cmp,
\s*NotCond\);""",
    """Value *CmpV = Builder.CreateICmp(
            Pred, Other, Constant::getNullValue(Other->getType()));
          Value *NotCondV = NotCond;
          if (CmpV->getType() != NotCond->getType())
            if (auto *VT = dyn_cast<VectorType>(CmpV->getType()))
              NotCondV = Builder.CreateVectorSplat(VT->getElementCount(), NotCond);
          return BinaryOperator::Create(
              Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, CmpV,
              NotCondV);""",
    s, flags=re.M)

p.write_text(s)
print("Patched", p)
PY
